class MKAverage {
    constructor(m, k) {
        this.m = m;
        this.k = k;
        this.sum = 0;
        this.minSet = new Set();
        this.midSet = new Set();
        this.maxSet = new Set();
        this.q = [];
    }

    addElement(num) {
        if (this.q.length === this.m) {
            this.removeElement();
        }

        this.minSet.add(num);
        this.sum += num;

        if (this.minSet.size > this.k) {
            let temp = Math.max(...this.minSet);
            this.minSet.delete(temp);
            this.midSet.add(temp);
            this.sum += temp;
        }

        if (this.midSet.size && Math.max(...this.minSet) > Math.min(...this.midSet)) {
            let temp1 = Math.max(...this.minSet);
            let temp2 = Math.min(...this.midSet);
            this.minSet.delete(temp1);
            this.midSet.delete(temp2);
            this.minSet.add(temp2);
            this.midSet.add(temp1);
            this.sum += temp2 - temp1;
        }

        const maxVal = Math.max(...this.midSet);
        this.maxSet.add(maxVal);
        this.sum -= maxVal;
        this.midSet.delete(maxVal);

        if (this.maxSet.size > this.k) {
            let temp = Math.min(...this.maxSet);
            this.maxSet.delete(temp);
            this.midSet.add(temp);
            this.sum += temp;
        }

        this.q.push(num);
    }

    calculateMKAverage() {
        if (this.q.length < this.m) {
            return -1;
        }
        return Math.floor(this.sum / (this.m - 2 * this.k));
    }

    removeElement() {
        const temp = this.q.shift();

        if (this.minSet.has(temp)) {
            this.minSet.delete(temp);
        } else if (this.midSet.has(temp)) {
            this.midSet.delete(temp);
            this.sum -= temp;
        } else {
            this.maxSet.delete(temp);
        }
    }
}
```


    - Initialize variables including m, k, sum and three sets: minSet, midSet and maxSet.
- For `addElement()`:
    1. Remove an element if the queue size equals m.
    2. Add the new element to minSet, update the sum.
    3. Adjust the elements between minSet, midSet, and maxSet. Ensure after each adding there are k elements in minSet and maxSet, and the rest in midSet.
- For `calculateMKAverage()`, check if the queue size is less than m, return -1. Otherwise, calculate and return the average value of the elements in midSet.
- For `removeElement()`, remove the element from minSet, midSet or maxSet according to the corresponding set.

