import java.util.*;

class MKAverage {
    int m, k;
    long sum = 0;
    TreeSet<Integer> minSet, midSet, maxSet;
    Queue<Integer> q;

    public MKAverage(int m, int k) {
        this.m = m;
        this.k = k;
        this.minSet = new TreeSet<>();
        this.midSet = new TreeSet<>();
        this.maxSet = new TreeSet<>();
        this.q = new LinkedList<>();
    }

    public void addElement(int num) {
        if (q.size() == m) {
            removeElement();
        }

        minSet.add(num);
        sum += num;

        if (minSet.size() > k) {
            int temp = minSet.last();
            minSet.remove(temp);
            midSet.add(temp);
            sum += temp;
        }

        if (!midSet.isEmpty() && minSet.last() > midSet.first()) {
            int temp1 = minSet.last();
            int temp2 = midSet.first();
            minSet.remove(temp1);
            midSet.remove(temp2);
            minSet.add(temp2);
            midSet.add(temp1);
            sum += temp2 - temp1;
        }

        maxSet.add(midSet.last());
        sum -= midSet.last();
        midSet.remove(midSet.last());

        if (maxSet.size() > k) {
            int temp = maxSet.first();
            maxSet.remove(temp);
            midSet.add(temp);
            sum += temp;
        }

        q.add(num);
    }

    public int calculateMKAverage() {
        if (q.size() < m) {
            return -1;
        }
        return (int) (sum / (m - 2 * k));
    }

    void removeElement() {
        int temp = q.poll();

        if (minSet.contains(temp)) {
            minSet.remove(temp);
        } else if (midSet.contains(temp)) {
            midSet.remove(temp);
            sum -= temp;
        } else {
            maxSet.remove(temp);
        }
    }
}
```


